ee:message.ee:set-payload:
%dw 2.0
output application/json

var embedding       = (vars.generatedEmbedding joinBy ",")
var service_call_id = vars.refinedPayload.serviceCallId
var limit           = 50
---
{
    "query": "SELECT service_call_id FROM service_calls_test WHERE service_call_id != '$(service_call_id)' AND search_embedding IS NOT NULL ORDER BY search_embedding <=> '[$(embedding)]'::vector LIMIT $(limit)"
}

%dw 2.0
output application/json

var callIds = (vars.similarCallIds map ("'" ++ $ ++ "'")) joinBy ', '
var total   = sizeOf(vars.similarCallIds default [])
var limit   = 100
---
{
    "query": "SELECT m.material_id::text, m.itemnmbr, m.itemdesc, m.item_category, m.usage_count, m.material_tier, COUNT(DISTINCT sit.service_call_id) AS hit_count, COUNT(DISTINCT sit.service_call_id)::float / $(total) AS freq_score FROM hvac_service_items_test sit JOIN hvac_materials m ON m.material_id = sit.material_id WHERE sit.service_call_id = ANY(ARRAY[$(callIds)]) AND m.is_active = true AND m.material_tier <= 4 GROUP BY m.material_id, m.itemnmbr, m.itemdesc, m.item_category, m.usage_count, m.material_tier ORDER BY hit_count DESC, m.usage_count DESC LIMIT $(limit)"
}

%dw 2.0
output application/json

var embedding = (vars.generatedEmbedding joinBy ",")
var matIds    = (vars.materials map ("'" ++ $.material_id ++ "'")) joinBy ', '
---
{
    "query": "SELECT material_id::text, 1 - (item_embedding <=> '[$(embedding)]'::vector) AS vector_sim FROM hvac_materials WHERE material_id = ANY(ARRAY[$(matIds)]::uuid[]) AND item_embedding IS NOT NULL"
}

ee:variables.ee:set-variable:
%dw 2.0
output application/java
---
if (isEmpty(payload)) {}
else payload reduce ((row, acc = {}) ->
    acc ++ {(row.material_id): (row.vector_sim default 0.0) as Number}
)

ee:message.ee:set-payload:
%dw 2.0
output application/json
---
{
    "query": "SELECT MAX(usage_count) AS max_usage FROM hvac_materials WHERE is_active = true"
}

%dw 2.0
output application/json
---
{
    "query": "SELECT material_id::text, itemnmbr, itemdesc, item_category, usage_count, material_tier FROM hvac_materials WHERE is_active = true AND material_tier = 1 ORDER BY usage_count DESC"
}

ee:variables.ee:set-variable:
%dw 2.0
output application/java

var VECTOR_WEIGHT = 0.50
var FREQ_WEIGHT   = 0.35
var POP_WEIGHT    = 0.15
var TOP_K         = 15

var materials    = vars.materials    default []
var vectorSimMap = vars.vectorSimMap default {}
var maxUsage     = vars.maxUsage     default 1
var topKCalls    = sizeOf(vars.similarCallIds default [])

---
((materials map (mat) -> do {
    var mid        = mat.material_id
    var isInjected = mat.injected default false

    // For injected universal items: no vector sim, no freq — score by popularity only
    // For regular candidates: full three-signal scoring
    var vectorSim  = if (isInjected) 0.0
                     else (vectorSimMap[mid] default 0.0) as Number

    var freqScore  = if (isInjected) 0.0
                     else (mat.freq_score default 0.0) as Number

    var hitCount   = if (isInjected) 0
                     else (mat.hit_count default 0) as Number

    var popScore   = ((mat.usage_count default 0) as Number) / (maxUsage as Number)

    var finalScore = if (isInjected)
                       // Universal items: partial freq weight + pop so they rank
                       // below freq-boosted items but above pure gap-fills
                       (FREQ_WEIGHT * 0.2) + (POP_WEIGHT * popScore)
                     else
                       (VECTOR_WEIGHT * vectorSim)
                       + (FREQ_WEIGHT  * freqScore)
                       + (POP_WEIGHT   * popScore)

    var reasons = if (isInjected)
                    ["Standard consumable — used on " ++ ((mat.usage_count default 0) as String) ++ " service calls"]
                  else (
                    (if (freqScore > 0)
                        ["Used in " ++ (hitCount as String) ++ "/" ++ (topKCalls as String) ++ " similar calls"]
                    else [])
                    ++ ["Semantic similarity: " ++ (vectorSim as String {format: "0.000"})]
                  )
    ---
    mat ++ {
        vector_sim  : vectorSim,
        freq_score  : freqScore,
        pop_score   : popScore,
        final_score : finalScore,
        reasons     : reasons
    }
}) orderBy -$.final_score)
  filter ((item, index) -> index < TOP_K)
